// Matches the existing Add to Cart button styling but uses a distinct color
// to visually differentiate "this goes to PDP" from "this adds to cart directly"
.matrix-choose-options-button {
    // Inherit all base styles from the existing .cart-add-to-cart-button-button class
    // (which is already applied via the shared class name)
    // Override the background color to differentiate from Add to Cart
    background-color: #00aeef !important;
    border-color: #00aeef !important;
    color: #ffffff !important;
    text-decoration: none !important;
