			border-color: #005abb !important;
			color: #fff !important;
			text-decoration: none !important;
    }
    &:focus,
    &:active {
        background-color: #005abb !important;
		border-color: #005abb !important;
		color: #fff !important;
		text-decoration: none !important;
        outline: none;
    }
}

